import React, { useEffect, useRef } from 'react'
import './styles.css'
import useProgressBarStore from './useProgressBarStore'

function ProgressBar({ id, idx }) {
    const { progressBars, completeProgressBar } = useProgressBarStore((state) => state)
    const progressBarRef = useRef(null)
    const hasStarted = useRef(false)

    function runProgressBar() {
        const progressBar = progressBarRef.current
        if (!progressBar) return
        let width = 0
        let rafId

        function updateWidth() {
            if (width < 100) {
                width += 1
                progressBar.style.width = width + '%'
                rafId = requestAnimationFrame(updateWidth)
            } else {
                completeProgressBar(id)
            }
        }

        rafId = requestAnimationFrame(updateWidth)
        return () => cancelAnimationFrame(rafId)
    }

    useEffect(() => {
        if (hasStarted.current) return

        const prevBar = progressBars.find(pb => pb.idx === idx - 1)
        const shouldStart = idx === 0 || (prevBar && prevBar.completed)

        if (shouldStart) {
            hasStarted.current = true
            return runProgressBar()
        }
    }, [progressBars])

    return (
        <>
            <div className="progress-bar-container">
                <div className='progress-bar' ref={progressBarRef}></div>
            </div>
        </>
    )
}

export default ProgressBar
